from collections import deque

def can_transform(x, y):
    if x == y:
        return True

    forward = {x}
    backward = {y}
    fq = deque([x])
    bq = deque([y])

    LIMIT = 2 * 10**18

    for _ in range(128):
        if not fq and not bq:
            break
        if fq:
            current = fq.popleft()
            binary = bin(current)[2:]
            for bit in ['0', '1']:
                nb = binary + bit
                rb = nb[::-1].lstrip('0') or '0'
                nv = int(rb, 2)
                if nv in backward:
                    return True
                if nv not in forward and nv <= LIMIT:
                    forward.add(nv)
                    fq.append(nv)
        if bq:
            current = bq.popleft()
            binary = bin(current)[2:]
            rb = binary[::-1]
            for trim in range(1, 3):
                candidate = rb[:-trim] if trim < len(rb) else ''
                if not candidate:
                    continue
                candidate = candidate.lstrip('0')
                if not candidate:
                    continue
                nv = int(candidate, 2)
                if nv in forward:
                    return True
                if nv not in backward and nv <= LIMIT:
                    backward.add(nv)
                    bq.append(nv)

    return False

x, y = map(int, input().split())
print("YES" if can_transform(x, y) else "NO")

